solutions.javascript:
var arrayRankTransform = function(arr) {
    if (!arr.length) return [];
    const sorted = [...new Set(arr)].sort((a, b) => a - b);
    const rank = new Map();
    sorted.forEach((v, i) => rank.set(v, i + 1));
    return arr.map(v => rank.get(v));
};
